amp;#x27;&lt;/span> &lt;span class=\&quot;hljs-keyword\&quot;>in&lt;/span> inspect.signature(dmoe.dMoE.forward).parameters&quot;,&quot;&quot;,&quot;&quot;,&quot;&quot;,&quot;&lt;span class=\&quot;hljs-comment\&quot;># adapted from flash attention, added safe serialization option for hf models&lt;/span>&quot;,&quot;&lt;span class=\&quot;hljs-keyword\&quot;>def&lt;/span> &lt;span class=\&quot;hljs-title function_\&quot;>state_dict_from_pretrained&lt;/span>(&lt;span class=\&quot;hljs-params\&quot;>model_name, safe_serialization=&lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>, device=&lt;span class=\&quot;hljs-literal\&quot;>None&lt;/span>, dtype=&lt;span class=\&quot;hljs-literal\&quot;>None&lt;/span>&lt;/span>):&quot;,&quot;    &lt;span class=\&quot;hljs-comment\&quot;># If not fp32, then we don&amp;#x27;t want to load directly to the GPU&lt;/span>&quot;,&quot;    mapped_device = &lt;span class=\&quot;hljs-string\&quot;>&amp;quot;cpu&amp;quot;&lt;/span> &lt;span class=\&quot;hljs-keyword\&quot;>if&lt;/span> dtype &lt;span class=\&quot;hljs-keyword\&quot;>not&lt;/span> &lt;span class=\&quot;hljs-keyword\&quot;>in&lt;/span> [torch.float32, &lt;span class=\&quot;hljs-literal\&quot;>None&lt;/span>] &lt;span class=\&quot;hljs-keyword\&quot;>else&lt;/span> device&quot;,&quot;    is_sharded = &lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>&quot;,&quot;    load_safe = &lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>&quot;,&quot;    resolved_archive_file = &lt;span class=\&quot;hljs-literal\&quot;>None&lt;/span>&quot;,&quot;&quot;,&quot;    weights_path = os.path.join(model_name, WEIGHTS_NAME)&quot;,&quot;    weights_index_path = os.path.join(model_name, WEIGHTS_INDEX_NAME)&quot;,&quot;    safe_weights_path = os.path.join(model_name, SAFE_WEIGHTS_NAME)&quot;,&quot;    safe_weights_index_path = os.path.join(model_name, SAFE_WEIGHTS_INDEX_NAME)&quot;,&quot;&quot;,&quot;    &lt;span class=\&quot;hljs-keyword\&quot;>if&lt;/span> os.path.isfile(weights_path):&quot;,&quot;        resolved_archive_file = cached_file(model_name, WEIGHTS_NAME, _raise_exceptions_for_missing_entries=&lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>)&quot;,&quot;    &lt;span class=\&quot;hljs-keyword\&quot;>elif&lt;/span> os.path.isfile(weights_index_path):&quot;,&quot;        resolved_archive_file = cached_file(model_name, WEIGHTS_INDEX_NAME, _raise_exceptions_for_missing_entries=&lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>)&quot;,&quot;        is_sharded = &lt;span class=\&quot;hljs-literal\&quot;>True&lt;/span>&quot;,&quot;    &lt;span class=\&quot;hljs-keyword\&quot;>elif&lt;/span> os.path.isfile(safe_weights_path):&quot;,&quot;        resolved_archive_file = cached_file(model_name, SAFE_WEIGHTS_NAME, _raise_exceptions_for_missing_entries=&lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>)&quot;,&quot;        load_safe = &lt;span class=\&quot;hljs-literal\&quot;>True&lt;/span>&quot;,&quot;    &lt;span class=\&quot;hljs-keyword\&quot;>elif&lt;/span> os.path.isfile(safe_weights_index_path):&quot;,&quot;        resolved_archive_file = cached_file(&quot;,&quot;            model_name, SAFE_WEIGHTS_INDEX_NAME, _raise_exceptions_for_missing_entries=&lt;span class=\&quot;hljs-literal\&quot;>False&lt;/span>&quot;,&quot;        )&quot;,&quot;        is_sharded = &lt;span class=\&quot;hljs-literal\&quot;>True&lt;/span>&quot;,&quot;        load_safe = &lt;span class=\&quot;hljs-literal\&quot;>True&lt;/span>&quot;,&quot;    &lt;span class=\&quot;hljs-keyword\&quot;>else&lt;/span>:  &lt;span class=\&quot;hljs-comment\&quot;># Try loading from HF hub instead of from local files&lt;/span>&quot;,&quot;        resolved_archive_file = &lt;span class=\&quot;hljs-literal\&quot;>None&lt;/span>&quot;,&quot;        &lt;span class=\&quot;hljs-keyword\&quot;>for&lt;/span> weight_name &lt;span class=\&quot;hljs-keyword\&quot;>in&lt;/span> [WEIGHTS_NAME, SAFE_WEIGHTS_NAME, WEIGHTS_INDEX_NAME, SAFE_WEIGHTS_INDEX_NAME]:&quot;,&quot;   